class Solution:
    def discountPrices(self, sentence: str, discount: int) -> str:
        words = sentence.split()
        result = []
        for word in words:
            if word.startswith('$') and word[1:].isdigit():
                price = float(word[1:])
                discount_price = price * (1 - discount / 100)
                result.append(f"${discount_price:.2f}")
            else:
                result.append(word)
        return ' '.join(result)
